attempt_count = 0
@retry(max_attempts=3)
def test_flaky():
    global attempt_count
    attempt_count += 1
    if attempt_count < 3:
        raise ValueError("fail")
    return "ok"
assert test_flaky() == "ok"
assert attempt_count == 3

@retry(max_attempts=1)
def always_fails():
    raise RuntimeError("boom")
try:
    always_fails()
    assert False, "Should have raised"
except RuntimeError:
    pass
